mapper.select:
SELECT ,
       e.enterprise_name AS enterprise_name,
       at.task_title AS task_title
FROM aw_rectification_track t
LEFT JOIN ent_enterprise e ON e.id = t.enterprise_id AND e.deleted = 0
LEFT JOIN aw_audit_task at ON at.id = t.task_id AND at.deleted = 0
WHERE t.deleted = 0

    AND t.task_id = #{taskId}


    AND t.enterprise_id = #{enterpriseId}


    AND t.audit_year = #{auditYear}


    AND t.status = #{status}

ORDER BY t.create_time DESC

mapper.update:
UPDATE aw_rectification_track
SET status = #{status}, update_time = NOW(), update_by = #{updateBy}
WHERE deleted = 0 AND id IN

    #{id}
